import sys


def read_data():
    n, p, q = map(int, input().split())
    s = input()
    return n, p, q, s


def check(s, p, q):
    return (p + q) == len(s)


def solve(s, p, q):
    if not check(s, p, q):
        return -1

    res = []
    i = 0
    while i < len(s):
        if i + p <= len(s):
            res.append(s[i:i + p])
            i += p
        else:
            res.append(s[i:])
            break
    return res


def main():
    n, p, q, s = read_data()
    res = solve(s, p, q)
    if res == -1:
        print(res)
    else:
        print(len(res))
        for i in res:
            print(i)


if __name__ == '__main__':
    main()
